sed -i "s/const \[downloadStatus, setDownloadStatus\] = useState<Record<string, 'idle' | 'second' | 'finish' | 'open' | 'save'>>({});/const [downloadStatus, setDownloadStatus] = useState<Record<string, 'idle' | 'second' | 'finish' | 'open' | 'save'>>(() => {\n    const saved = localStorage.getItem('ios_store_download_status');\n    return saved ? JSON.parse(saved) : {};\n  });\n\n  useEffect(() => {\n    localStorage.setItem('ios_store_download_status', JSON.stringify(downloadStatus));\n  }, [downloadStatus]);/g" src/App.tsx
